// E03S07 — AC2, AC3: Build canonical On Site customer SMS
// Template: '[Business Name]: Your technician has arrived.'
// AC3: business_name ALWAYS from clients table — never hardcoded

const businessName = $('GET Client Details').item.json.business_name;
const customerPhone = $('Split In Items').item.json.customer_phone;
const twilioFromNumber = $('GET Client Details').item.json.twilio_number;

// Validate required fields — fail loudly, not silently
if (!businessName) throw new Error('[E03S07] Missing clients.business_name — cannot build On Site SMS');
if (!customerPhone) throw new Error('[E03S07] customer_phone missing — should not reach Build SMS Body (check IF node wiring)');

// AC2: Exact template from story AC2
// '[Business Name]: Your technician has arrived.'
const smsBody = businessName + ': Your technician has arrived.';

return [{
  json: {
    smsBody: smsBody,
    customerPhone: customerPhone,
    twilioFromNumber: twilioFromNumber
  }
}];
